const GENERIC_ALLOCATION_KEYS = new Set(["tipperary", "supermacs", "hegartys", "clonroche"]);

export function normaliseZeviFundingKey(value) {
  return String(value || "")
    .toLowerCase()
    .replace(/&/g, " and ")
    .replace(/[^a-z0-9]+/g, " ")
    .replace(/(ltd|limited|ireland|co|county|ev|charger|charging|dc|kw|kwh)/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function recordKeys(record) {
  return [record.siteName, record.address, ...(record.aliases || [])]
    .map(normaliseZeviFundingKey)
    .filter(Boolean);
}

const ALLOCATION_KEY_COUNTS = ZEVI_ALLOCATION_REFERENCE.reduce((acc, record) => {
  const key = normaliseZeviFundingKey(record.siteName);
  if (key) acc.set(key, (acc.get(key) || 0) + 1);
  return acc;
}, new Map());

function contextKeys(context = {}) {
  const site = context.site || context;
  return [
    context.portfolioSiteId,
    site.id,
    site.name,
    site.siteName,
    site.address,
    site.display_address,
    site.liveActuals?.siteName,
    context.name,
    context.siteName,
    context.address,
    context.searchText,
    context.rawName,
    ...(Array.isArray(context.aliases) ? context.aliases : []),
    ...(Array.isArray(site.aliases) ? site.aliases : [])
  ].map(normaliseZeviFundingKey).filter(Boolean);
}

function isSafeAllocationAutoApply(record, matchedKey) {
  const key = normaliseZeviFundingKey(record.siteName);
  const tokens = key.split(" ").filter(Boolean);
  if (!key || ALLOCATION_KEY_COUNTS.get(key) > 1) return false;
  if (GENERIC_ALLOCATION_KEYS.has(key)) return false;
  if (tokens.length < 2) return false;
  if (!matchedKey || matchedKey !== key) return false;
  return true;
}

function decorate(record, matchType, matchedOn, autoApply, extra = {}) {
  return {
    ...record,
    matchType,
    matchedOn,
    autoApply: !!autoApply,
    sourceLabel: record.sourceType === "confirmed-matched" ? "ZEVI confirmed matched funding" : "ZEVI allocation reference",
    confidenceLabel: record.confidence === "confirmed" ? "Confirmed" : record.confidence === "medium" ? "Medium — review recommended" : "Allocation exact/reference"
  , ...extra };
}

export function zeviFundingForSite(context = {}, options = {}) {
  const site = context.site || context;
  const portfolioSiteId = String(context.portfolioSiteId || site.id || site.portfolioSiteId || "");
  if (portfolioSiteId) {
    const direct = ZEVI_CONFIRMED_FUNDING.find(record => record.portfolioSiteId && record.portfolioSiteId === portfolioSiteId);
    if (direct) return decorate(direct, "portfolio-site-id", portfolioSiteId, true);
  }
  const keys = contextKeys(context);
  for (const key of keys) {
    const direct = ZEVI_CONFIRMED_FUNDING.find(record => recordKeys(record).includes(key));
    if (direct) return decorate(direct, "confirmed-alias", key, true);
  }
  if (options.allowAllocationExact !== false) {
    for (const key of keys) {
      const allocation = ZEVI_ALLOCATION_REFERENCE.find(record => normaliseZeviFundingKey(record.siteName) === key);
      if (allocation) {
        const autoApply = isSafeAllocationAutoApply(allocation, key);
        return decorate(allocation, "allocation-exact", key, autoApply, autoApply ? {} : { reviewRequired: true });
      }
    }
  }
  return null;
}

export function zeviFundingSuggestionsForSite(context = {}, options = {}) {
  const keys = contextKeys(context).filter(k => k.length >= 6);
  const suggestions = [];
  const seen = new Set();
  const consider = [...ZEVI_CONFIRMED_FUNDING, ...(options.includeAllocation === false ? [] : ZEVI_ALLOCATION_REFERENCE)];
  for (const record of consider) {
    const rkeys = recordKeys(record);
    for (const key of keys) {
      const hit = rkeys.find(rk => rk.length >= 6 && (rk.includes(key) || key.includes(rk)));
      if (!hit) continue;
      if (seen.has(record.id)) continue;
      seen.add(record.id);
      const allocationKey = normaliseZeviFundingKey(record.siteName);
      const safeAuto = record.sourceType === "confirmed-matched" || isSafeAllocationAutoApply(record, allocationKey);
      suggestions.push(decorate(record, record.sourceType === "confirmed-matched" ? "possible-confirmed" : "possible-allocation", key, false, { reviewRequired: !safeAuto }));
      break;
    }
  }
  return suggestions.slice(0, 5);
}

export function zeviFundingShortLabel(match) {
  if (!match) return "No ZEVI funding match";
  const amount = Number(match.grantAmount || 0).toLocaleString("en-IE", { maximumFractionDigits: 0 });
  const scheme = match.scheme ? `${match.scheme} · ` : "";
  return `${scheme}€${amount} · ${match.chargersFunded || 0} charger${Number(match.chargersFunded) === 1 ? "" : "s"} / ${match.evSpacesFunded || 0} EV spaces`;
}
